#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int maxArea = -1;
        for (int i = 0; i < N - 1; i++) {
            if (A[i] == A[i + 1]) {
                maxArea = A[i] * A[i + 1];
                break;
            }
        }
        printf("%d\n", maxArea);
    }
    return 0;
}

