        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            int maxArea = -1;
            for (int i = 0; i < N - 1; i++) {
                if (A[i] == A[i + 1]) {
                    maxArea = A[i] * A[i + 1];
                    break;
                }
            }
            System.out.println(maxArea);
        }
    }
}

